glass main() -> Int {
  shield {
    pour("authorized");
  }
  return 0;
}

glass main() -> Int {
  drink val: Any = sanitize("user input");
  pour(val);
  return 0;
}

glass main() -> Int {
  drink val: Any = armor(42);
  pour(val);
  return 0;
}

glass main() -> Int {
  drink val: Any = morph("data");
  pour(val);
  return 0;
}

glass main() -> Int {
  drink val: Any = detect("payload");
  pour(val);
  return 0;
}

glass main() -> Int {
  defend(parched);
  pour("safe");
  return 0;
}

glass main() -> Int {
  defend(quenched);
  pour("never");
  return 0;
}

glass main() -> Int {
  shield {
    shield {
      pour("nested");
    }
  }
  return 0;
}

glass main() -> Int {
  spillage {
    drink s: Any = sanitize("");
    pour("ok");
  } cleanup (e: Error) {
    pour("error");
  }
  return 0;
}

glass main() -> Int {
  drink v: Any = morph(armor("secret"));
  pour(v);
  return 0;
}
